}}];

const token = $('Get Token [Init]').first().json.tenant_access_token;
const src = $('Set Init Data').first().json;
return [{ json: {
  ...src,
  lark_token: token,
  searchBody: JSON.stringify({"filter":{"conjunction":"and","conditions":[{"field_name":"Job No.","operator":"is","value":[src.job_id]}]}})
}}];

const prep = $('Prep [Init]').first().json;
const token = prep.lark_token;
const src = prep;
const data = $input.first().json;
const txt = (v) => { if (!v) return ''; if (typeof v === 'string') return v; if (typeof v === 'number') return String(v); if (v.value !== undefined && Array.isArray(v.value)) { if (v.value.length === 0) return ''; const first = v.value[0]; if (typeof first === 'string') return first; if (first?.text) return first.text; if (first?.name) return first.name; } if (Array.isArray(v)) { if (v.length === 0) return ''; const first = v[0]; if (typeof first === 'string') return first; if (first?.text) return first.text; if (first?.name) return first.name; } if (v.text) return v.text; if (v.name) return v.name; return ''; };
const items = data.data?.items || [];
if (items.length === 0) {
  return [{ json: { ...src, t5_record_id: '', shop_name: src.customer_name, maps_url: src.job_maps_url, line_id: src.customer_line_id, customer_id: '', lark_token: token } }];
}
const item = items[0];
const f = item.fields || {};
return [{ json: {
  ...src,
  t5_record_id: item.record_id,
  shop_name: txt(f['Shop Name']) || src.customer_name,
  maps_url: txt(f['Google Maps URL']) || src.job_maps_url,
  line_id: src.customer_line_id || txt(f['C.LINE User ID']),
  customer_id: txt(f['Customer ID']) || '',
  lark_token: token
} }];

