const updateBody = JSON.stringify({fields:{Status:'ถึงแล้ว','Arrived Time':src.arrived_at_ms,'Customer Notified - Arrived':src.arrived_at_ms}});
const lineText = '🔧 ช่างถึงร้านแล้วครับ!\n\n📋 รหัสงาน: ' + src.job_id + '\n👷 ช่าง ' + src.tech_name + ' ถึงร้านแล้วครับ 🙏';
