return [{ json: {
  adminBody: JSON.stringify({"to": "C40b37d81f4e199a7b7357537166a1efd", "messages": [{"type": "text", "text": text}]})
}}];

const ADMIN_IDS = ['e5d154gc', 'eceffed6', 'a978af6f'];
const src = $('Parse T5 [Arrived]').first().json;
const token = $('Get Token [Arrived]').first().json.tenant_access_token;
const text = '📍 ช่างถึงแล้ว!\n\n' +
  '📋 รหัสงาน: ' + (src.job_id || '-') + '\n' +
  '👷 ช่าง: ' + (src.tech_name || '-') + '\n' +
