const q = $input.first().json.query || {};
const jobId = (q.job_id || '').toString().trim();
if (!jobId) return [{ json: { found: false, error: 'no job_id' } }];
return [{ json: { job_id: jobId } }];

const jobId = $('Extract Job ID').first().json.job_id;
const allRows = $input.all();
const jobRows = allRows.filter(r => r.json['Job No.'] === jobId);
const withPos = jobRows.filter(r => (parseFloat(r.json['Tech GPS Lat']) || 0) !== 0);
if (withPos.length === 0) {
  return [{ json: { found: false, lat: 0, lng: 0, status: 'traveling', timestamp: '' } }];
}
const latest = withPos[withPos.length - 1];
const lat = parseFloat(latest.json['Tech GPS Lat']) || 0;
const lng = parseFloat(latest.json['Tech GPS Lng']) || 0;
return [{ json: {
  found: lat !== 0 || lng !== 0,
  job_id: jobId,
  lat,
  lng,
  status: latest.json['Status'] || 'traveling',
  timestamp: latest.json['Timestamp'] || '',
  tech_name: latest.json['Tech Name'] || '',
  customer_name: latest.json['Shop Name'] || ''
}}];

return [{ json: { html: `<!DOCTYPE html>
<html lang="th">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1,user-scalable=no">
<title>ติดตามช่าง — SK ICE</title>
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<style>
*{margin:0;padding:0;box-sizing:border-box}
html,body{height:100%;overflow:hidden;font-family:'Helvetica Neue',Arial,sans-serif;background:#F0F4F8}
body{display:flex;flex-direction:column}
.hdr{background:linear-gradient(135deg,#1E3A5F,#2E6DA4);padding:13px 16px;color:#fff;text-align:center;flex-shrink:0}
.hdr h1{font-size:17px;font-weight:700}.hdr p{font-size:12px;color:#A8D5F0;margin-top:2px}
.sbar{background:#fff;padding:11px 16px;display:flex;align-items:center;gap:10px;box-shadow:0 2px 6px rgba(0,0,0,.12);flex-shrink:0}
.si{font-size:26px}.sinfo{flex:1}
.st{font-size:15px;font-weight:700;color:#2C3E50}
.ss{font-size:12px;color:#888;margin-top:2px;display:flex;align-items:center;gap:5px}
.dot{display:inline-block;width:8px;height:8px;border-radius:50%;background:#27AE60;flex-shrink:0}
.dot.off{background:#ccc}
@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
.dot.on{animation:pulse 1.5s infinite}
.tag{font-size:11px;background:#EEF4FF;color:#2E6DA4;padding:3px 8px;border-radius:10px;font-weight:700;flex-shrink:0}
.wrap{flex:1;position:relative;min-height:0}
#map{width:100%;height:100%}
.fabs{position:absolute;bottom:20px;right:14px;z-index:1000;display:flex;flex-direction:column;gap:10px;align-items:flex-end}
.fab{border:none;border-radius:50px;padding:11px 16px;font-size:14px;font-weight:700;cursor:pointer;box-shadow:0 3px 12px rgba(0,0,0,.25);display:flex;align-items:center;gap:6px;white-space:nowrap}
.fab-tech{background:#1E3A5F;color:#fff}
.fab-me{background:#2E6DA4;color:#fff}
</style>
</head>
<body>
<div class="hdr"><h1>🧊 SK ICE — ติดตามช่าง</h1><p id="hdr-sub">กำลังโหลด...</p></div>
<div class="sbar">
  <div class="si" id="s-icon">🚗</div>
  <div class="sinfo">
    <div class="st" id="s-text">กำลังเดินทาง</div>
    <div class="ss"><span class="dot on" id="dot"></span><span id="s-sub">กำลังโหลดตำแหน่ง...</span></div>
  </div>
  <span class="tag" id="job-tag">-</span>
</div>
<div class="wrap">
  <div id="map"></div>
  <div class="fabs">
    <button class="fab fab-tech" id="btn-tech" onclick="focusTech()" style="display:none">🚗 ตำแหน่งช่าง</button>
    <button class="fab fab-me" onclick="centerMe()">📍 ตำแหน่งฉัน</button>
  </div>
</div>
<script>
const GPS_POS_URL = 'https://n8n-production-b8f6.up.railway.app/webhook/gps-position';
const POLL_MS = 60000;
const p = new URLSearchParams(location.search);
const JOB = (p.get('job_id') || p.get('work') || '').trim();
document.getElementById('hdr-sub').textContent = JOB ? 'งาน: ' + JOB : '-';
document.getElementById('job-tag').textContent = JOB || '-';
const map = L.map('map',{zoomControl:true,attributionControl:false});
L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png',{maxZoom:19,subdomains:'abcd'}).addTo(map);
map.setView([13.75,100.5],13);
const techIcon=L.divIcon({html:'<div style="font-size:30px;line-height:1">🚗</div>',className:'',iconSize:[34,34],iconAnchor:[17,17]});
const doneIcon=L.divIcon({html:'<div style="font-size:30px;line-height:1">✅</div>',className:'',iconSize:[34,34],iconAnchor:[17,17]});
let techMarker=null,myMarker=null,techLat=null,techLng=null,myLat=null,myLng=null,firstLoad=true,done=false,pollTimer=null;
function fetchPosition(){
  if(!JOB)return;
  fetch(GPS_POS_URL+'?job_id='+encodeURIComponent(JOB),{redirect:'follow'})
    .then(r=>r.json()).then(d=>{updateMap(d);updateStatus(d);}).catch(()=>{});
}
function updateMap(d){
  if(!d.found||!d.lat||d.lat===0)return;
  techLat=d.lat;techLng=d.lng;
  const ll=[d.lat,d.lng];
  const icon=d.status==='completed'?doneIcon:techIcon;
  if(!techMarker){techMarker=L.marker(ll,{icon}).addTo(map);document.getElementById('btn-tech').style.display='flex';}
  else{techMarker.setLatLng(ll);techMarker.setIcon(icon);}
  if(firstLoad){map.setView(ll,15);firstLoad=false;}
}
function updateStatus(d){
  const st=d.status||'traveling';
  if(st==='completed'){document.getElementById('s-icon').textContent='✅';document.getElementById('s-text').textContent='งานเสร็จแล้ว!';document.getElementById('s-sub').textContent='ขอบคุณที่ใช้บริการ SK ICE';document.getElementById('dot').className='dot off';if(!done){done=true;clearInterval(pollTimer);}}
  else if(st==='arrived'){document.getElementById('s-icon').textContent='🔧';document.getElementById('s-text').textContent='ช่างถึงที่แล้ว!';document.getElementById('s-sub').textContent='กำลังดำเนินการ';document.getElementById('dot').className='dot off';}
  else{document.getElementById('s-icon').textContent='🚗';document.getElementById('s-text').textContent='กำลังเดินทางมาหาคุณ';document.getElementById('s-sub').textContent='อัปเดตล่าสุด: '+(d.timestamp?new Date(d.timestamp).toLocaleTimeString('th-TH',{hour:'2-digit',minute:'2-digit'}):'-');document.getElementById('dot').className='dot on';}
}
function focusTech(){if(techLat!==null)map.setView([techLat,techLng],16);}
function centerMe(){
  if(myLat!==null){map.setView([myLat,myLng],17);return;}
  if(!navigator.geolocation){alert('เบราว์เซอร์ไม่รองรับ GPS');return;}
  navigator.geolocation.getCurrentPosition(pos=>{myLat=pos.coords.latitude;myLng=pos.coords.longitude;if(!myMarker){myMarker=L.marker([myLat,myLng]).addTo(map);}else{myMarker.setLatLng([myLat,myLng]);}map.setView([myLat,myLng],17);},()=>{alert('ไม่สามารถหาตำแหน่งของคุณได้');},{enableHighAccuracy:true,timeout:12000});
}
fetchPosition();
pollTimer=setInterval(fetchPosition,POLL_MS);
</script>
</body></html>` } }];
